export type TypeKind =
  | "query"
  | "mutation"
  | "subscription"
  | "object"
  | "interface"
  | "scalar"
  | "enum"
  | "union"
  | "field"
  | "input-object"
  | "inputObject"
  | "directive";

export function typeKindIcon(
  kind: TypeKind,
): (props: IconProps) => React.ReactElement {
  switch (kind) {
    case "query":
      return IconQuery;
    case "mutation":
      return IconMutation;
    case "subscription":
      return IconSubscription;
    case "interface":
      return IconInterface;
    case "scalar":
      return IconScalar;
    case "enum":
      return IconEnum;
    case "union":
      return IconUnion;
    case "field":
      return IconField;
    case "input-object":
    case "inputObject":
      return IconInputObject;
    case "directive":
      return IconDirective;
    case "object":
    default:
      return IconObject;
  }
}
